#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    for (int i = 0; i < M; i++) {
        int L, R, k;
        scanf("%d %d %d", &L, &R, &k);
        int freq[N + 1] = {0};
        int max_freq = 0, max_element = -1;
        for (int j = L - 1; j < R; j++) {
            freq[arr[j]]++;
            if (freq[arr[j]] > max_freq) {
                max_freq = freq[arr[j]];
                max_element = arr[j];
            }
        }
        if (max_freq >= k) {
            printf("%d\n", max_element);
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

