import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[] arr = new int[N];
        for (int i = 0; i < N; i++) {
            arr[i] = sc.nextInt();
        }
        for (int i = 0; i < M; i++) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int k = sc.nextInt();
            int[] freq = new int[N + 1];
            int max_freq = 0, max_element = -1;
            for (int j = L - 1; j < R; j++) {
                freq[arr[j]]++;
                if (freq[arr[j]] > max_freq) {
                    max_freq = freq[arr[j]];
                    max_element = arr[j];
                }
            }
            if (max_freq >= k) {
                System.out.println(max_element);
            } else {
                System.out.println(-1);
            }
        }
    }
}

